/**
 * ScratchEditor — редактор официального Scratch (scratch.mit.edu/projects/editor).
 * /scratch/edit       — новый проект (пустой шаблон)
 * /scratch/edit/:id   — редактируем существующий (загружаем .sb3 в редактор)
 *
 * Workflow для V1:
 * - Открывается scratch.mit.edu/projects/editor в новой вкладке
 * - Пользователь работает в настоящем Scratch
 * - Кнопка «💾 Сохранить» — учит ребёнка нажать Файл → Save to your computer
 * - Затем кнопка «✅ Зафиксировать в платформе» — пользователь выбирает скачанный файл, мы делаем upload
 *
 * Превью на странице остаётся через forkphorus — настоящий Scratch player
 * умеет встраивать только проекты, уже загруженные на scratch.mit.edu.
 *
 * V2 (потом): hosted scratch-gui npm + прямой save через VM API.
 */

import { useEffect, useRef, useState } from 'react'
import { useNavigate, useParams } from 'react-router-dom'
import PlatformShell from '../components/PlatformShell'
import { useToast } from '../hooks/useToast'
import { BASE } from '../api/client'
import { getAccessToken } from '../lib/authStorage'
import {
  getScratchProject, createScratchProject, updateScratchProject,
  submitScratchProject, type ScratchProjectDto,
} from '../api/scratchProjects'

export default function ScratchEditor() {
  const navigate = useNavigate()
  const { id } = useParams<{ id?: string }>()
  const { toast, show } = useToast()
  const fileInputRef = useRef<HTMLInputElement>(null)

  const [project, setProject] = useState<ScratchProjectDto | null>(null)
  const [title, setTitle] = useState('Новый проект')
  const [submitting, setSubmitting] = useState(false)

  // Scratch editor не принимает произвольный URL для загрузки чужого .sb3 —
  // открываем в новой вкладке официальный scratch.mit.edu/projects/editor;
  // ученик скачивает файл командой Файл → «Скачать на компьютер»
  // и потом загружает обратно через нашу кнопку «Загрузить .sb3».
  // На самой странице показываем встроенный плеер (forkphorus) с превью —
  // настоящий Scratch player встраивает только проекты с scratch.mit.edu по ID.
  const fileUrl = project
    ? `${BASE}/scratch-projects/${project.id}/file?token=${getAccessToken() ?? ''}`
    : null
  const previewUrl = fileUrl
    ? `https://forkphorus.github.io/embed.html?id=${encodeURIComponent(fileUrl)}`
    : null
  const editorOpenUrl = 'https://scratch.mit.edu/projects/editor/'

  useEffect(() => {
    if (!id) return
    getScratchProject(id)
      .then(({ project: p }) => { setProject(p); setTitle(p.title) })
      .catch(() => show('Проект не найден', 'error'))
  }, [id])

  async function handleSaveAs() {
    const file = fileInputRef.current?.files?.[0]
    if (!file) { show('Выбери .sb3 файл (скачай из редактора через File → Save to your computer)', 'error'); return }
    if (!file.name.endsWith('.sb3')) { show('Нужен .sb3 файл', 'error'); return }
    setSubmitting(true)
    try {
      const fd = new FormData()
      fd.append('file', file)
      fd.append('title', title)
      if (project) {
        await updateScratchProject(project.id, fd)
        show('Сохранено', 'success')
      } else {
        const created = await createScratchProject(fd)
        show('Создано', 'success')
        navigate(`/scratch/edit/${created.id}`, { replace: true })
        setProject(created)
      }
      if (fileInputRef.current) fileInputRef.current.value = ''
    } catch (e) {
      show('Ошибка: ' + (e instanceof Error ? e.message : ''), 'error')
    } finally {
      setSubmitting(false)
    }
  }

  async function handleSubmit() {
    if (!project) { show('Сначала сохрани проект', 'error'); return }
    try {
      const updated = await submitScratchProject(project.id)
      setProject(updated)
      show('Сдано на проверку 🎉', 'success')
    } catch (e) {
      show('Ошибка: ' + (e instanceof Error ? e.message : ''), 'error')
    }
  }

  return (
    <PlatformShell>
      {toast && (
        <div role="status" style={{ position: 'fixed', top: 20, right: 20, zIndex: 9999, background: toast.kind === 'error' ? '#dc2626' : toast.kind === 'success' ? '#059669' : '#6b5ce7', color: '#fff', padding: '10px 20px', borderRadius: 12, fontSize: 14, fontWeight: 600 }}>{toast.msg}</div>
      )}

      <div style={{ maxWidth: 900, margin: '24px auto', padding: '0 16px', display: 'flex', flexDirection: 'column', gap: 16 }}>

        {/* Top bar */}
        <div style={{ display: 'flex', gap: 8, alignItems: 'center', flexWrap: 'wrap' }}>
          <button className="kb-btn" onClick={() => navigate('/scratch')}>← К моим проектам</button>
          <input value={title} onChange={(e) => setTitle(e.target.value)}
            style={{ flex: 1, minWidth: 200, padding: '8px 12px', borderRadius: 8, border: '1.5px solid var(--paper-3)', fontSize: 16, fontWeight: 700 }}
            placeholder="Название проекта" />
        </div>

        {/* 1. Открыть редактор */}
        <div className="kb-card" style={{ padding: 24, background: 'linear-gradient(135deg, #FF9454 0%, #E8517B 100%)', color: '#fff' }}>
          <h2 style={{ margin: 0, fontSize: 22, fontWeight: 900, fontFamily: 'var(--f-display)' }}>1. Сделай проект</h2>
          <p style={{ margin: '6px 0 16px', fontSize: 14, opacity: 0.9, lineHeight: 1.5 }}>
            Откроется настоящий Scratch от MIT. Перетаскивай блоки, меняй спрайты, программируй.
            {project && <><br/>Чтобы продолжить работать со <b>старым</b> проектом — сначала скачай его файл (кнопка «📥 Скачать .sb3») и в редакторе нажми <b>Файл → Загрузить с компьютера</b>.</>}
          </p>
          <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
            <a href={editorOpenUrl} target="_blank" rel="noreferrer"
              style={{ display: 'inline-block', background: '#fff', color: '#E8517B', fontWeight: 900, fontSize: 16, padding: '12px 28px', borderRadius: 12, textDecoration: 'none', boxShadow: '0 4px 0 rgba(0,0,0,0.15)' }}>
              🚀 Открыть редактор Scratch →
            </a>
            {fileUrl && (
              <a href={fileUrl} download
                style={{ display: 'inline-block', background: 'rgba(255,255,255,0.2)', color: '#fff', fontWeight: 700, fontSize: 14, padding: '12px 20px', borderRadius: 12, textDecoration: 'none', border: '1.5px solid #fff' }}>
                📥 Скачать .sb3
              </a>
            )}
          </div>
        </div>

        {/* 2. Загрузить обратно */}
        <div className="kb-card" style={{ padding: 24 }}>
          <h2 style={{ margin: 0, fontSize: 22, fontWeight: 900, fontFamily: 'var(--f-display)' }}>2. Сохрани в платформу</h2>
          <p style={{ margin: '6px 0 16px', fontSize: 14, color: 'var(--ink-soft)', lineHeight: 1.5 }}>
            В редакторе: <b>Файл → Сохранить на компьютер</b>. Затем выбери скачанный .sb3 ниже.
          </p>
          <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap', alignItems: 'center' }}>
            <input ref={fileInputRef} type="file" accept=".sb3" style={{ flex: 1, minWidth: 220 }} />
            <button className="kb-btn" style={{ background: '#FF9454', color: '#fff', fontWeight: 800, padding: '10px 22px', fontSize: 15 }} disabled={submitting} onClick={() => void handleSaveAs()}>
              {submitting ? '…' : '💾 Сохранить'}
            </button>
            {project && !project.submittedAt && (
              <button className="kb-btn" style={{ background: '#059669', color: '#fff', fontWeight: 800, padding: '10px 22px', fontSize: 15 }} onClick={() => void handleSubmit()}>
                ✅ Сдать учителю
              </button>
            )}
            {project?.submittedAt && (
              <span style={{ fontSize: 13, color: '#059669', fontWeight: 800, padding: '10px 14px', background: 'var(--mint-soft, #d1fae5)', borderRadius: 8 }}>
                ✓ Сдан учителю
              </span>
            )}
          </div>
        </div>

        {/* 3. Превью существующего */}
        {previewUrl && (
          <div className="kb-card" style={{ padding: 0, overflow: 'hidden' }}>
            <div style={{ padding: '12px 20px', borderBottom: '1px solid var(--paper-3)', fontSize: 13, fontWeight: 700, color: 'var(--ink-soft)' }}>
              Текущая версия проекта · превью
            </div>
            <iframe
              src={previewUrl}
              style={{ width: '100%', height: 480, border: 'none', display: 'block' }}
              title={title}
              allow="autoplay; fullscreen"
            />
          </div>
        )}
      </div>
    </PlatformShell>
  )
}
